const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// ============================================================================
// SECURE VERSION - Works immediately in development AND production
// ============================================================================
// Step 1: Set environment variables locally (one-time setup, ~30 seconds):
//   In local.settings.json (auto-excluded from git by .gitignore):
